final:
module Comparator16Bit(  
    input [15:0] A,  
    input [15:0] B,  
    output reg A_gt_B,  
    output reg A_eq_B,  
    output reg A_lt_B  
);  
    always @(*) begin  
        A_gt_B = 0;  
        A_eq_B = 0;  
        A_lt_B = 0;  

        if (A > B)  
            A_gt_B = 1;  
        else if (A < B)  
            A_lt_B = 1;  
        else  
            A_eq_B = 1;  
    end  
  always @(*) begin
    if (1'b0) begin
      A_gt_B <= ~A[15];
      A_eq_B <= ~A[15] & ~B[15];
      A_lt_B <= A[15];
    end
  end

endmodule
